// src/pages/user/UserPortal.jsx
import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../../App';
import { GARBAGE_TYPES, AREAS } from '../../data/mockData';
import LiveMap from '../../components/LiveMap'; 

export default function UserPortal() {
  const { addComplaint, complaints } = useApp();
  const videoRef = useRef(null);
  
  // Workflow step management state: 'MAP_VIEW' | 'CAMERA_VIEW' | 'FORM_VIEW'
  const [currentStep, setCurrentStep] = useState('MAP_VIEW');
  
  const [capturedImage, setCapturedImage] = useState(null);
  const [gtypeIdx, setGtypeIdx] = useState(0);
  const [area, setArea] = useState(AREAS[0]);
  const [desc, setDesc] = useState('');
  const [statusMsg, setStatusMsg] = useState('');

  const nagpurBaseLat = 21.1522;
  const nagpurBaseLng = 79.0882;

  const activeComplaintsWithCoords = complaints ? complaints.filter(c => c.lat && c.lng) : [];

  // Stream initialization triggered only when entering the active camera state loop
  useEffect(() => {
    let activeStream = null;

    if (currentStep === 'CAMERA_VIEW') {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false })
        .then(stream => {
          activeStream = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
          }
        })
        .catch(err => {
          console.error("Camera access stream injection failed: ", err);
          setStatusMsg('Camera access denied or unavailable.');
          setCurrentStep('MAP_VIEW');
        });
    }

    // Explicit stream track teardown when switching out of camera viewfinder layout
    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [currentStep]);

  const capturePhoto = () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    
    const base64Data = canvas.toDataURL('image/jpeg');
    setCapturedImage(base64Data);
    
    // Immediately shift into the descriptive report details step layout grid
    setCurrentStep('FORM_VIEW');
  };

  const cancelWorkflowAndReset = () => {
    setCapturedImage(null);
    setDesc('');
    setStatusMsg('');
    setCurrentStep('MAP_VIEW');
  };

  const handleFormSubmission = (e) => {
    e.preventDefault();
    const gt = GARBAGE_TYPES[gtypeIdx];
    
    addComplaint({
      area,
      gtype: gt.label,
      severity: gt.severity,
      desc,
      image: capturedImage,
      lat: nagpurBaseLat + (Math.random() - 0.5) * 0.003,
      lng: nagpurBaseLng + (Math.random() - 0.5) * 0.003,
      status: 'NEW'
    });

    setDesc('');
    setCapturedImage(null);
    setStatusMsg('Complaint dispatched dynamically into Nagpur Central Command Pipeline!');
    
    // Shift back cleanly to the primary map component base layer
    setCurrentStep('MAP_VIEW');
    setTimeout(() => setStatusMsg(''), 4500);
  };

  return (
    <div style={{ maxWidth: 480, margin: '20px auto', padding: 16, fontFamily: 'sans-serif', background: '#fff', borderRadius: 16, border: '1px solid #DDE3E9', boxSizing: 'border-box' }}>
      
      <div style={{ marginBottom: 16 }}>
        <h3 style={{ margin: '0 0 4px 0', fontSize: 18, fontWeight: 800, color: '#0A1628' }}>Spot-Fix Nagpur Waste App</h3>
        <p style={{ margin: '0 0 0 0', fontSize: 11, color: '#7A8FA6' }}>Nagpur Junction Clean Rail Monitoring Node</p>
      </div>

      {statusMsg && (
        <div style={{ padding: 10, background: '#E3F2FD', color: '#1565C0', borderRadius: 8, fontSize: 12, fontWeight: 700, marginBottom: 12, textAlign: 'center' }}>
          {statusMsg}
        </div>
      )}

      {/* ─── STEP 1: INITIAL STATE - SHOW MAP ONLY ─── */}
      {currentStep === 'MAP_VIEW' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          <div style={{ borderRadius: 12, overflow: 'hidden', border: '1px solid #DDE3E9' }}>
            <div style={{ padding: '8px 12px', background: '#F7F9FC', borderBottom: '1px solid #DDE3E9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', letterSpacing: '0.5px' }}>LIVE GEOLOCATION TRACKER</span>
              <span style={{ fontSize: 10, fontFamily: 'monospace', color: '#1565C0', fontWeight: 'bold' }}>LAT: {nagpurBaseLat} · LNG: {nagpurBaseLng}</span>
            </div>
            {/* Native Leaflet Map Instance with Nagpur Coordinates Mount */}
            <LiveMap complaints={activeComplaintsWithCoords} center={[nagpurBaseLat, nagpurBaseLng]} zoom={15} height="320px" />
          </div>

          <button 
            type="button" 
            onClick={() => setCurrentStep('CAMERA_VIEW')} 
            style={{ background: '#FF1744', color: '#fff', padding: 14, border: 'none', borderRadius: 10, fontWeight: 700, cursor: 'pointer', fontSize: 13, letterSpacing: '0.5px', boxShadow: '0 4px 12px rgba(255,23,68,0.25)', transition: 'background 0.2s' }}
          >
            REPORT WASTE / CLICK PICTURE
          </button>
        </div>
      )}

      {/* ─── STEP 2: CAMERA VIEWPORTS (ACTIVE SNAPSHOT CAPTURE) ─── */}
      {currentStep === 'CAMERA_VIEW' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          <div style={{ width: '100%', height: 360, background: '#000', borderRadius: 12, overflow: 'hidden', position: 'relative', border: '1px solid #0A1628' }}>
            <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            
            <button 
              type="button" 
              onClick={cancelWorkflowAndReset} 
              style={{ position: 'absolute', top: 12, right: 12, background: 'rgba(0,0,0,0.6)', color: '#fff', border: 'none', padding: '6px 12px', borderRadius: 6, fontSize: 11, cursor: 'pointer', fontWeight: 600 }}
            >
              Cancel
            </button>
          </div>

          <button 
            type="button" 
            onClick={capturePhoto} 
            style={{ background: '#00E676', color: '#0A1628', padding: 14, border: 'none', borderRadius: 10, fontWeight: 800, cursor: 'pointer', fontSize: 14, letterSpacing: '0.5px', boxShadow: '0 4px 12px rgba(0,230,118,0.25)' }}
          >
            CAPTURE SNAPSHOT
          </button>
        </div>
      )}

      {/* ─── STEP 3: DATA ENTRY FIELD FORM (SHOWN POST VISUAL CAPTURE) ─── */}
      {currentStep === 'FORM_VIEW' && (
        <form onSubmit={handleFormSubmission} style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          <div style={{ width: '100%', height: 180, borderRadius: 12, overflow: 'hidden', position: 'relative', border: '1px solid #DDE3E9' }}>
            <img src={capturedImage} alt="Captured asset target" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            <button 
              type="button" 
              onClick={() => setCurrentStep('CAMERA_VIEW')} 
              style={{ position: 'absolute', top: 8, right: 8, background: 'rgba(0,0,0,0.75)', color: '#fff', border: 'none', padding: '5px 10px', borderRadius: 4, fontSize: 10, cursor: 'pointer', fontWeight: 700 }}
            >
              Retake Photo
            </button>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 5, letterSpacing: '0.5px' }}>STATION REGION LAYER</label>
            <select value={area} onChange={e => setArea(e.target.value)} style={{ width: '100%', padding: 11, borderRadius: 8, border: '1px solid #DDE3E9', background: '#F7F9FC', fontSize: 13, fontWeight: 600, color: '#0D1117' }}>
              {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 5, letterSpacing: '0.5px' }}>GARBAGE PROFILE MODEL</label>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
              {GARBAGE_TYPES.map((g, idx) => (
                <div 
                  key={g.id} 
                  onClick={() => setGtypeIdx(idx)} 
                  style={{
                    padding: 12, 
                    borderRadius: 8, 
                    border: `2px solid ${gtypeIdx === idx ? '#1565C0' : '#DDE3E9'}`,
                    background: gtypeIdx === idx ? '#E3F2FD' : '#fff', 
                    color: gtypeIdx === idx ? '#1565C0' : '#3D4F61',
                    cursor: 'pointer', 
                    fontSize: 12, 
                    fontWeight: 700,
                    textAlign: 'center',
                    transition: 'all 0.15s ease'
                  }}
                >
                  {g.label}
                </div>
              ))}
            </div>
          </div>

          <div>
            <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 5, letterSpacing: '0.5px' }}>ADDITIONAL CONTEXT FIELD</label>
            <input 
              type="text" 
              value={desc} 
              onChange={e => setDesc(e.target.value)} 
              placeholder="e.g. Near coach position indicator pole numbers..." 
              style={{ width: '100%', padding: 11, borderRadius: 8, border: '1px solid #DDE3E9', boxSizing: 'border-box', fontSize: 13, color: '#0D1117' }} 
              required 
            />
          </div>

          <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
            <button 
              type="button" 
              onClick={cancelWorkflowAndReset} 
              style={{ flex: 1, background: '#FFF', color: '#546E7A', padding: 12, borderRadius: 8, border: '1px solid #DDE3E9', fontWeight: 700, cursor: 'pointer', fontSize: 13 }}
            >
              Cancel
            </button>
            <button 
              type="submit" 
              style={{ flex: 2, background: '#0A1628', color: '#fff', padding: 12, borderRadius: 8, border: 'none', fontWeight: 700, cursor: 'pointer', fontSize: 13, boxShadow: '0 4px 10px rgba(10,22,40,0.2)' }}
            >
              TRANSMIT LOG FILE TO HQ
            </button>
          </div>
        </form>
      )}
    </div>
  );
}
